import Transport from './transport/transport';
export type Level = 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'fatal';
export interface CoreLoggerOptions {
    name?: string;
    level?: Level;
    transports?: Array<Transport>;
    formatData?: (data: LogData) => string;
    transformData?: (data: LogData) => LogData;
    callSiteFrameIndex?: number;
    flushInterval?: number;
}
export interface LoggerOptions extends CoreLoggerOptions {
    enableConsoleLog?: boolean;
    enableFileLog?: boolean;
    consoleTransportOptions?: ConsoleTransportOptions;
    fileTransportOptions?: FileTransportOptions;
}
export interface TransportOptions {
    name?: string;
    level?: Level;
}
export type ConsoleTransportOptions = TransportOptions;
export interface FileTransportOptions extends TransportOptions {
    file?: string;
}
export interface LogData {
    level: Level;
    pid: number;
    version: string;
    timestamp: number;
    datetime: string;
    hostIP: string;
    ipv4: string;
    ipv6: string;
    location: string;
    msg?: string | Error;
    message?: string;
    stack?: string;
    splats?: any[];
    logId?: string;
    tags: {
        [key: string]: any;
    };
    [key: string]: any;
}
export interface BaseLogData {
    level: Level;
    msg?: string | Error;
    logId?: string;
    location?: string;
    splats?: any[];
    tags?: {
        [key: string]: any;
    };
    [key: string]: any;
}
